#!/usr/bin/env node
/**
 * ProductHunt gallery — 7 images at 1270×760 (PH standard)
 *
 * 1. Hero shot — dashboard splash with KPIs
 * 2. AI invoice generation — modal in action (best-effort: invoice detail page)
 * 3. Pipeline kanban — key differentiation
 * 4. Time tracker — work/time page
 * 5. Mobile responsive showcase — composite (separate file generated by composer)
 * 6. Multi-language — RU+EN side-by-side (composite)
 * 7. Hero shot RU — variant
 */
const fs = require('fs')
const path = require('path')
const { chromium } = require('/Users/myoffice/lancerwise/node_modules/playwright')

const COOKIE_VALUE = fs.readFileSync('/tmp/qa_comprehensive_cookie.txt', 'utf8').trim()
const COOKIE_NAME = 'sb-skfgwyzarrhhkzvltbgm-auth-token'
const BASE = 'https://www.lancerwise.com'

const PH_WIDTH = 1270
const PH_HEIGHT = 760

const SAMPLE_INVOICE_ID = '40cef5fd-0012-4fda-8b13-aaf236971ef5'

// Browser viewport must be > target size to ensure full page captured; we crop after via PNG resize? No,
// just set viewport directly to 1270x760
const SHOTS = [
  { name: 'ph-01-dashboard-hero',       url: '/dashboard',                          locale: 'en' },
  { name: 'ph-02-invoice-detail-en',    url: `/invoices/${SAMPLE_INVOICE_ID}`,      locale: 'en' },
  { name: 'ph-03-pipeline-kanban',      url: '/clients/pipeline',                   locale: 'en' },
  { name: 'ph-04-time-tracker',         url: '/work/time',                          locale: 'en' },
  { name: 'ph-05-invoices-list',        url: '/invoices',                           locale: 'en' },
  { name: 'ph-06-dashboard-ru',         url: '/dashboard',                          locale: 'ru' },
  { name: 'ph-07-contracts-list',       url: '/contracts',                          locale: 'en' },
]

const OUT_DIR = path.join(__dirname, 'ph-gallery')
if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true })

async function captureShot(browser, shot) {
  const ctx = await browser.newContext({
    viewport: { width: PH_WIDTH, height: PH_HEIGHT },
    locale: shot.locale === 'ru' ? 'ru-RU' : 'en-US',
    extraHTTPHeaders: {
      'Accept-Language': shot.locale === 'ru' ? 'ru-RU,ru;q=0.9' : 'en-US,en;q=0.9',
    },
  })

  await ctx.addCookies([
    { name: COOKIE_NAME, value: COOKIE_VALUE, domain: '.lancerwise.com', path: '/', secure: true, sameSite: 'Lax' },
    { name: 'NEXT_LOCALE', value: shot.locale, domain: '.lancerwise.com', path: '/', secure: true, sameSite: 'Lax' },
    { name: 'cookie-consent-v1', value: 'accepted', domain: '.lancerwise.com', path: '/', secure: true, sameSite: 'Lax' },
    { name: 'cookieConsent', value: 'accepted', domain: '.lancerwise.com', path: '/', secure: true, sameSite: 'Lax' },
    { name: 'lw-cookie-consent', value: 'accepted', domain: '.lancerwise.com', path: '/', secure: true, sameSite: 'Lax' },
  ])

  await ctx.addInitScript(() => {
    try {
      localStorage.setItem('welcome-tour-completed', 'true')
      localStorage.setItem('lw-welcome-tour-completed', 'true')
      localStorage.setItem('lw-welcome-tour-dismissed', 'true')
      localStorage.setItem('welcome_tour_completed_at', new Date().toISOString())
      localStorage.setItem('cookie-consent-v1', JSON.stringify({
        status: 'accepted', essential: true, analytics: false, marketing: false, ts: Date.now(),
      }))
      localStorage.setItem('cookieConsent', 'accepted')
      localStorage.setItem('lw-cookie-consent', 'accepted')
    } catch {}
  })

  const page = await ctx.newPage()
  const fpath = path.join(OUT_DIR, `${shot.name}.png`)
  try {
    await page.goto(BASE + shot.url, { waitUntil: 'domcontentloaded', timeout: 45000 })
    await page.waitForLoadState('networkidle', { timeout: 20000 }).catch(() => {})
    await page.waitForTimeout(1800)
    await page.keyboard.press('Escape').catch(() => {})

    await page.addStyleTag({
      content: `
        [class*="cookie-banner" i], [class*="CookieBanner" i],
        [data-testid*="cookie" i], [role="dialog"][aria-label*="cookie" i] { display: none !important; }
        [class*="welcome-tour" i], [class*="WelcomeTour" i],
        [data-testid*="welcome-tour" i], [role="dialog"][aria-label*="welcome" i],
        [role="dialog"][aria-label*="tour" i] { display: none !important; }
      `,
    }).catch(() => {})

    await page.waitForTimeout(400)
    await page.screenshot({ path: fpath, fullPage: false })
    console.log(`[OK]   ${shot.name}.png`)
  } catch (e) {
    console.log(`[FAIL] ${shot.name} → ${e.message.split('\n')[0]}`)
  } finally {
    await ctx.close()
  }
}

;(async () => {
  console.log(`Capturing ${SHOTS.length} PH gallery shots at ${PH_WIDTH}×${PH_HEIGHT}`)
  const browser = await chromium.launch({ headless: true })
  for (const shot of SHOTS) {
    await captureShot(browser, shot)
  }
  await browser.close()
  console.log('done.')
})()
